mapper.select:
SELECT d.id, d.category_id AS categoryId, kc.name AS categoryName, d.title, d.document_code AS documentCode, d.owner_dept AS ownerDept, d.status, d.current_version_id AS currentVersionId, d.summary, v.version_no AS currentVersionNo, v.parse_status, v.vector_status, v.chunk_count AS chunkCount, d.created_at AS createdAt, d.updated_at AS updatedAt FROM knowledge_document d LEFT JOIN knowledge_document_version v ON d.current_version_id = v.id AND v.del_flag = 0 LEFT JOIN knowledge_category kc on d.category_id = kc.id AND kc.del_flag = 0 WHERE d.del_flag = 0
AND ( d.title LIKE CONCAT('%', #{query.keyword}, '%') OR d.document_code LIKE CONCAT('%', #{query.keyword}, '%') OR d.summary LIKE CONCAT('%', #{query.keyword}, '%') )
AND d.category_id = #{query.categoryId}
AND d.status = #{query.status}
AND d.owner_dept LIKE CONCAT('%', #{query.ownerDept}, '%')
AND v.vector_status = #{query.vectorStatus}
ORDER BY d.created_at DESC
